const jobDesc = $('Job Input').first().json.job_description_raw || '';
const _prompt = 'Extract structured job information from this job description. Return ONLY a valid JSON object with these exact keys: company_name, job_title, location, job_requirements, tech_stack, job_description_clean. Keep values concise.\n\nJob Description:\n' + jobDesc;
return [{ json: {
  prompt: _prompt,
  body: JSON.stringify({
    model: 'llama-3.1-8b-instant',
    messages: [{ role: 'user', content: _prompt }],
    temperature: 0.7,
    max_tokens: 2048
  })
} }];

// WHY: Parse Groq's JSON response and merge with CV + metadata
const groqResponse = $input.first().json;
const content = groqResponse.choices[0].message.content;

// WHY: Strip markdown code fences if Groq wraps JSON in ```json blocks
const clean = content.replace(/```json/g, '').replace(/```/g, '').trim();

let extracted = {};
try {
  extracted = JSON.parse(clean);
} catch(e) {
  // Fallback if JSON parse fails
  extracted = {
    company_name: 'Unknown Company',
    job_title: 'Unknown Title',
    location: '',
    job_requirements: '',
    tech_stack: '',
    job_description_clean: $('Job Input').item.json.job_description_raw
  };
}

// Get CV text from previous node
const cvText = $('Fetch CV from GitHub').item.json.data || 
               $('Fetch CV from GitHub').item.json || '';

const cvString = typeof cvText === 'string' ? cvText : JSON.stringify(cvText);

// Skills override - if user typed something in Job Input, use that; else use CV
const skillsOverride = $('Job Input').item.json.skills_override || '';

// Generate application ID and date metadata
const id = 'app-' + Date.now() + '-' + Math.random().toString(36).substring(2, 9);
const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const appliedDate = year + '-' + month + '-' + day;

const companyName = extracted.company_name || 'Unknown';
const jobTitle = extracted.job_title || 'Unknown';

// WHY: Folder name used for GitHub commit path structure
const folderName = day + '_' + 
  companyName.replace(/[^a-zA-Z0-9]/g, '_') + '_' + 
  jobTitle.replace(/[^a-zA-Z0-9]/g, '_');

return [{
  json: {
    application_id: id,
    company_name: companyName,
    job_title: jobTitle,
    location: extracted.location || '',
    job_url: $('Job Input').item.json.job_url || '',
    job_description: extracted.job_description_clean || $('Job Input').item.json.job_description_raw,
    job_requirements: extracted.job_requirements || '',
    tech_stack: extracted.tech_stack || '',
    user_skills: skillsOverride || cvString,
    cv_text: cvString,
    applied_date: appliedDate,
    year: year,
    month: month,
    day: day,
    folder_name: folderName
  }
}];

