const d = $('Parse Job Fields').first().json;
const cv = (d.cv_text || '').substring(0, 800);
const _prompt = 'You must respond with ONLY a raw JSON object, no explanation, no markdown, no text before or after. The JSON must have exactly these keys: overall_score (integer 0-100), technical_match (integer 0-100), experience_match (integer 0-100), top_strengths (array of exactly 3 strings), critical_gaps (array of exactly 3 strings), recommendation (string). Example format: {"overall_score":75,"technical_match":80,"experience_match":70,"top_strengths":["a","b","c"],"critical_gaps":["x","y","z"],"recommendation":"text"}. Now calculate job fit for:\n\nRequirements: ' + d.job_requirements + '\nTech: ' + d.tech_stack + '\n\nCV:\n' + cv;
