const jobData = $('Parse Job Fields').first().json;
const safe = (val) => (val == null ? '' : String(val));

// WHY: T1 runs sequentially. Read each result by node name.
// $input only has the last node's output (T1 Job Fit Score).
const resume = $('T1 Resume Analysis').first().json?.choices?.[0]?.message?.content || '[Resume analysis failed]';
const coverLetter = $('T1 Cover Letter').first().json?.choices?.[0]?.message?.content || '[Cover letter failed]';
const fitRaw = $('T1 Job Fit Score').first().json?.choices?.[0]?.message?.content || '{}';

let fitScore = {};
try {
  const cleanFit = fitRaw.replace(/```json/g, '').replace(/```/g, '').trim();
  fitScore = JSON.parse(cleanFit);
} catch(e) {
  fitScore = { overall_score: 0, recommendation: 'Score parsing failed' };
}

const metadataContent = 
  '# Application: ' + safe(jobData.company_name) + ' - ' + safe(jobData.job_title) + '\n\n' +
  '- Company: ' + safe(jobData.company_name) + '\n' +
  '- Title: ' + safe(jobData.job_title) + '\n' +
  '- Location: ' + safe(jobData.location) + '\n' +
  '- URL: ' + safe(jobData.job_url) + '\n' +
  '- Applied: ' + safe(jobData.applied_date) + '\n' +
  '- Application ID: ' + safe(jobData.application_id) + '\n' +
  '- **Job Fit Score: ' + (fitScore.overall_score || 0) + '%**\n' +
  '- Recommendation: ' + safe(fitScore.recommendation) + '\n\n' +
  '## Top Strengths\n' +
  (fitScore.top_strengths || []).map(s => '- ' + s).join('\n') + '\n\n' +
  '## Critical Gaps\n' +
  (fitScore.critical_gaps || []).map(g => '- ' + g).join('\n') + '\n\n' +
  '## Job Description\n' + safe(jobData.job_description) + '\n\n' +
  '## Requirements\n' + safe(jobData.job_requirements) + '\n';

const resumeContent = '# Resume Analysis - ' + safe(jobData.job_title) + ' at ' + safe(jobData.company_name) + '\n\n' + resume;
const coverLetterContent = '# Cover Letter - ' + safe(jobData.company_name) + '\n\n' + coverLetter;

return [{
  json: {
    ...jobData,
    tier1_status: 'complete',
    fit_score: fitScore.overall_score || 0,
    fit_recommendation: fitScore.recommendation || '',
    fit_strengths: fitScore.top_strengths || [],
    fit_gaps: fitScore.critical_gaps || [],
    resume_preview: resume.substring(0, 300),
    metadata_content: metadataContent,
    resume_content: resumeContent,
    cover_letter_content: coverLetterContent
  }
}];

const tierData = $input.first().json;
const resumeText = (tierData.resume_content || '').toLowerCase();

const keywordCategories = {
  'Cloud Platforms': ['aws', 'ec2', 's3', 'lambda', 'rds', 'gcp', 'compute engine', 'cloud run', 'azure'],
  'Containerization': ['docker', 'kubernetes', 'k8s', 'helm', 'container'],
  'CI/CD': ['github actions', 'gitlab ci', 'jenkins', 'circleci', 'ci/cd', 'pipeline'],
  'Architecture': ['microservices', 'distributed', 'scalability', 'load balancing', 'system design', 'rest api', 'graphql'],
  'Databases': ['sql', 'nosql', 'redis', 'postgresql', 'mongodb', 'elasticsearch'],
  'Testing': ['jest', 'vitest', 'cypress', 'playwright', 'unit test', 'integration test', 'e2e'],
  'Code Quality': ['typescript', 'eslint', 'solid', 'code review', 'type safety'],
  'Monitoring': ['datadog', 'elk', 'observability', 'logging', 'prometheus', 'grafana'],
  'DevOps': ['terraform', 'infrastructure as code', 'ansible', 'devops']
};

const present = [];
const missing = [];

for (const [category, keywords] of Object.entries(keywordCategories)) {
  const found = keywords.filter(kw => resumeText.includes(kw));
  const notFound = keywords.filter(kw => !resumeText.includes(kw));
  if (found.length > 0) present.push('**' + category + '**: ' + found.join(', '));
  if (notFound.length > 0) missing.push('**' + category + '**: ' + notFound.join(', '));
}

const score = Math.round((present.length / (present.length + missing.length)) * 100);

const atsContent =
  '# ATS Keyword Analysis - ' + (tierData.company_name || '') + '\n\n' +
  '## ATS Score: ' + score + '%\n\n' +
  '## Keywords Present (' + present.length + ')\n' +
  present.map(k => '- ' + k).join('\n') + '\n\n' +
  '## Missing Keywords (' + missing.length + ') - ADD THESE\n' +
  missing.map(k => '- ' + k).join('\n') + '\n\n' +
  '## Recommendation\n' +
  (score < 50 ? 'CRITICAL: Needs significant ATS optimization.' :
   score < 70 ? 'MODERATE: Add missing keywords naturally.' :
   'GOOD: Strong ATS coverage.') + '\n';

return [{
  json: {
    ...tierData,
    ats_score: score,
    ats_content: atsContent,
    resume_content: (tierData.resume_content || '') + '\n\n---\n\n' + atsContent
  }
}];

