const d = $('Parse Job Fields').first().json;
const repoItems = $('T4 Fetch GitHub Repos').all();
const repos = repoItems.map(i => i.json).filter(r => r && r.name);

// WHY include all available metadata:
// The /users/repos API doesn't return README content or file listings.
// We pass everything it DOES return so the AI makes accurate assessments.
// Crucially: tell the AI what it CANNOT know to stop it from guessing.
const repoList = repos.map(r =>
  'Repo: ' + r.name + '\n'
  + '  Language: ' + (r.language || 'N/A') + '\n'
  + '  Description: ' + (r.description || '[no description]') + '\n'
  + '  Topics: ' + (r.topics && r.topics.length > 0 ? r.topics.join(', ') : '[none]') + '\n'
  + '  Stars: ' + (r.stargazers_count || 0) + '\n'
  + '  Forks: ' + (r.forks_count || 0) + '\n'
  + '  Open issues: ' + (r.open_issues_count || 0) + '\n'
  + '  Size (KB): ' + (r.size || 0) + '\n'
  + '  Has wiki: ' + (r.has_wiki ? 'yes' : 'no') + '\n'
  + '  Is fork: ' + (r.fork ? 'yes' : 'no') + '\n'
  + '  URL: ' + (r.html_url || '') + '\n'
).join('\n');

const _prompt =
  'You are a senior engineering hiring manager analyzing a candidate\'s GitHub portfolio.\n\n'
  + 'Job: ' + d.job_title + ' at ' + d.company_name + '\n'
  + 'Requirements: ' + d.job_requirements + '\n\n'
  + 'CANDIDATE\'S ACTUAL GITHUB REPOS (use ONLY these, never invent repos):\n'
  + repoList + '\n\n'
  + 'IMPORTANT CONSTRAINTS:\n'
  + '- You do NOT have access to the actual code, README files, or test files.\n'
  + '- You CAN infer from: description, topics, language, size, forks, open issues.\n'
  + '- A repo with no description likely has no README — flag it.\n'
  + '- A repo with size < 50KB and no description is likely undocumented — flag it.\n'
  + '- Do NOT say "no tests" unless you have evidence. Say "tests not visible from metadata" instead.\n\n'
  + 'Your task:\n'
  + '1. Pick the top 3-5 repos most relevant to this role. For each:\n'
  + '   - WHY it is relevant (connect to specific job requirements)\n'
  + '   - Technical signals visible from the metadata\n'
  + '   - Resume bullet: strong action verb + metric (use real metrics from description if present)\n'
