  '- [ ] Day 7 follow-up: ' + fu2 + '\n' +
  '- [ ] Day 30 check-in: ' + fu3 + '\n' +
  '- [ ] 90-day check-in: ' + fu4 + '\n\n' +
  '## Interview Stages\n' +
  '- [ ] Phone Screen\n' +
  '- [ ] Technical Interview\n' +
  '- [ ] System Design Round\n' +
  '- [ ] Final Round\n' +
  '- [ ] Offer\n\n' +
  '## Status Updates\n' +
  '| Date | Status | Notes |\n' +
  '|------|--------|-------|\n' +
  '| ' + appliedDate + ' | Applied | Initial application submitted |\n\n' +
  '## Contacts\n' +
  '- Recruiter: \n' +
  '- Hiring Manager: \n' +
  '- Referral: \n\n' +
  '## Notes\n' +
  '_Add notes after each interaction_\n';

const analyticsContent =
  '# Analytics Update - ' + appliedDate + '\n\n' +
  '## New Application\n' +
  '- Company: ' + jobData.company_name + '\n' +
  '- Role: ' + jobData.job_title + '\n' +
  '- Location: ' + jobData.location + '\n' +
  '- Date: ' + appliedDate + '\n' +
  '- Fit Score: ' + fitScore + '%\n' +
  '- Status: Applied\n';

// WHY return only T5's unique keys: same reason as Tier 2, 3, 4.
return [{
  json: {
    tier5_status: 'complete',
    tracking_content: trackingContent,
    analytics_content: analyticsContent,
    followup_day3: fu1,
    followup_day7: fu2,
    followup_day30: fu3,
    followup_day90: fu4
  }
}];

// WHY fully sequential chain: T1 -> T2 -> T3 -> T4 -> T5 -> here.
// By the time Tier 5 fires this node, all 5 tiers are guaranteed complete.
// We read each tier's compiled output node by name -- no $input.all() needed,
// no race conditions, no try/catch needed.

const t1 = $('ATS Keyword Optimization').first().json || {};
const t2 = $('Tier 2 - Cold Outreach').first().json || {};
const t3 = $('Tier 3 - Interview Prep').first().json || {};
const t4 = $('Tier 4 - Portfolio Matching').first().json || {};
const t5 = $('Tier 5 - Database & Tracking').first().json || {};
const t6 = $('Tier 6 - Tailored Resume').first().json || {};

// WHY T1 first in Object.assign: T1 carries the base job metadata.
// Each tier adds unique keys (cold_email_content, interview_prep_content,
// portfolio_content, tracking_content) so there are no meaningful collisions.
const merged = Object.assign({}, t1, t2, t3, t4, t5, t6);
return [{ json: merged }];

// WHY: Merge Results feeds all tier data here as multiple items
// We merge them all into one jobData object
const allItems = $input.all();
let jobData = {};
for (const item of allItems) {
  jobData = Object.assign({}, jobData, item.json);
}

const safe = (val) => val || '';
const company = safe(jobData.company_name).replace(/[^a-zA-Z0-9]/g, '_') || 'Unknown';
const safeCompany = company + '_' + (jobData.applied_date||'').replace(/-/g,'');

const frontmatter = `---
company: "${safe(jobData.company_name)}"
role: "${safe(jobData.job_title)}"
applied_date: "${safe(jobData.applied_date)}"
status: "applied"
job_link: "${safe(jobData.job_url)}"
location: "${safe(jobData.location)}"
