ats_score: ${jobData.ats_score || 0}
application_id: "${safe(jobData.application_id)}"
tags: [job-search, ${new Date().getFullYear()}]
---`;

const content = frontmatter + `

# ${safe(jobData.company_name)} - ${safe(jobData.job_title)}

## Application Status
| Field | Value |
