_Add your notes here after each interaction_
`;

const contentBase64 = Buffer.from(content).toString('base64');
const filePath = 'Job_Applications/Active/' + safeCompany + '.md';

return [{
  json: {
    ...jobData,
    file_path: filePath,
    file_content_base64: contentBase64,
    commit_message: 'New application: ' + safe(jobData.company_name) + ' - ' + safe(jobData.job_title) + ' | Fit: ' + (jobData.fit_score||0) + '%',
    vault_path: filePath
  }
}];

const prepData = $('Prepare Git Content').first().json;
const resp = $input.first().json;
const success = resp.content && resp.content.sha;
return [{
  json: {
    ...prepData,
    git_status: success ? 'success' : 'error',
    commit_sha: resp.commit ? resp.commit.sha : '',
    git_error: success ? '' : JSON.stringify(resp).substring(0, 200)
  }
}];

const fileResp = $input.first().json;
const prepData = $('Prepare Git Content').first().json;
const existingSha = fileResp.sha || null;
return [{ json: { ...prepData, existing_sha: existingSha } }];

// WHY read Git Commit Result by node name:
// We need the new application's data (company, role, fit score etc.)
// to add to the Recent Activity section of the dashboard.
const newApp = $('Git Commit Result').first().json;
const today = new Date().toISOString().split('T')[0];

// Parse the Active folder listing
// GitHub returns one item per file when listing a directory
const items = $input.all();
const activeFiles = Array.isArray(items[0]?.json)
  ? items[0].json
  : items.map(i => i.json).filter(f => f && f.type === 'file' && f.name && f.name.endsWith('.md'));

const activeCount = activeFiles.length;

// Build upcoming follow-ups for the new application
const safe = v => v || '';
const company = safe(newApp.company_name);
const role = safe(newApp.job_title);
const fitScore = newApp.fit_score || 0;
const appliedDate = safe(newApp.applied_date);
const filePath = safe(newApp.vault_path);

// Build quick links from active files
const quickLinks = activeFiles
  .map(f => '- [[' + f.name.replace('.md', '') + ']]')
  .join('\n');

// Build upcoming follow-ups from the new application
const followups = [
  { label: 'Day 3', date: safe(newApp.followup_day3), company },
  { label: 'Day 7', date: safe(newApp.followup_day7), company },
  { label: 'Day 30', date: safe(newApp.followup_day30), company },
  { label: 'Day 90', date: safe(newApp.followup_day90), company },
].filter(f => f.date);

const followupRows = followups
  .map(f => '| ' + f.date + ' | ' + f.company + ' | ' + f.label + ' | ⏳ Pending |')
  .join('\n');

const dashContent =
  '---\n'
  + 'updated: "' + today + '"\n'
  + 'tags: [dashboard, job-search]\n'
  + '---\n\n'
  + '# 📊 Job Search Dashboard\n'
