  + '## 📈 Overview\n'
  + '| Status | Count |\n'
  + '|--------|-------|\n'
  + '| 🟢 Active | ' + activeCount + ' |\n'
  + '| 🟡 Waiting | — |\n'
  + '| 🔵 Offers | — |\n'
  + '| ❌ Rejected | — |\n'
  + '| **Total** | **' + activeCount + '** |\n\n'
  + '## ⚡ Recent Activity\n'
  + '| Date | Company | Role | Fit Score |\n'
  + '|------|---------|------|-----------|\n'
  + '| ' + appliedDate + ' | ' + company + ' | ' + role + ' | ' + fitScore + '% |\n\n'
  + '## 📅 Upcoming Follow-Ups\n'
  + '| Due Date | Company | Type | Status |\n'
  + '|----------|---------|------|--------|\n'
  + followupRows + '\n\n'
  + '## 🔗 Active Applications\n'
  + quickLinks + '\n';

const contentBase64 = Buffer.from(dashContent).toString('base64');

return [{ json: {
  ...newApp,
  dashboard_path: 'Dashboard/Main_Dashboard.md',
  dashboard_content_base64: contentBase64,
  dashboard_commit_message: 'Dashboard updated: ' + company + ' - ' + role + ' | ' + today
} }];

const d = $('Parse Job Fields').first().json;

// WHY full CV (4000 chars): T6 writes the actual resume so it needs complete
// project details, not just a truncated snippet like T1's analysis.
const fullCV = (d.cv_text || '').substring(0, 4000);

// WHY portfolio_analysis_clean not portfolio_content:
// portfolio_content starts with repo listing which wastes tokens.
// portfolio_analysis_clean is just the AI analysis with resume bullets.
const t4Data = $('Tier 4 - Portfolio Matching').first().json || {};
const portfolioAnalysis = t4Data.portfolio_analysis_clean || t4Data.portfolio_content || '';

// WHY include repo list separately:
// Not all projects appear in the CV -- the GitHub repo list is the
// authoritative source. T6 can use these to add projects the CV is missing.
const repoItems = $('T4 Fetch GitHub Repos').all();
const repoListForResume = repoItems
  .map(i => i.json)
  .filter(r => r && r.name && r.description)
  .map(r => '- ' + r.name + ': ' + r.description + ' (' + (r.language || 'N/A') + ')')
  .join('\n');

// ATS gaps from ATS node
const atsData = $('ATS Keyword Optimization').first().json || {};
const atsMissing = (atsData.ats_content || '').split('## Missing Keywords')[1]?.split('## Recommendation')[0] || '';

const prompt =
  'You are a Senior Technical Recruiter & Hiring Manager with 15+ years at Google, Meta, and NVIDIA Israel. '
  + 'You have reviewed thousands of CVs for Junior Software Engineering roles in the Israeli market.\n\n'
  + 'Your task: Write a COMPLETE tailored resume. This is not analysis — produce the actual document, ready to send.\n\n'
  + '=== JOB TARGET ===\n'
  + 'Company: ' + d.company_name + '\n'
  + 'Role: ' + d.job_title + '\n'
  + 'Requirements: ' + d.job_requirements + '\n\n'
  + '=== ORIGINAL CV (keep this exact structure and format) ===\n'
  + fullCV + '\n\n'
  + '=== ALL GITHUB REPOS (source of truth for projects — use even if not in CV) ===\n'
  + repoListForResume + '\n\n'
  + '=== PORTFOLIO ANALYSIS (relevance ranking + resume bullet guidance) ===\n'
  + portfolioAnalysis + '\n\n'
  + '=== RULES ===\n'
  + '1. Keep the EXACT same structure and sections as the original CV.\n'
  + '2. Same format per project: Name — Domain | Tech1 · Tech2 · Tech3, then bullet points.\n'
  + '3. Rewrite bullet points using Google XYZ formula: Accomplished [X] as measured by [Y], by doing [Z]. '
  + 'Lead with impact metric first. Use the portfolio analysis above for framing guidance.\n'
  + '4. NEVER invent numbers. Keep all original metrics: 258x, 37-point, 55%, 5.5x, etc.\n'
  + '5. Rewrite the summary section as a SENIOR ENGINEER would write it — not as a student applying. '
  + 'Read the full CV and pick the single most impressive quantified achievement for THIS role (' + d.job_title + ' at ' + d.company_name + ') — choose based on relevance, not just the biggest number. Lead with that. '
  + 'Second sentence: what you build and what problem domain you work in. '
  + 'Third sentence: why ' + d.company_name + ' specifically (one concrete technical reason, not "innovative environment"). '
  + 'BANNED phrases in summary: excited to apply, confident in my ability, looking forward, '
  + 'dynamic environment, passionate about, would love to, strong fit. '
  + 'Tone: declarative, not pleading. Own your achievements.\n'
  + '6. Reorder projects: most relevant to this role first.\n'
  + '7. For ATS keywords below that are NOT in the candidates real skills — '
  + 'add this warning comment next to the Skills section: '
  + '> ⚠️ ATS GAP: [keyword] — not in actual experience, do not include without real background\n'
  + 'ATS gaps:\n' + atsMissing + '\n'
  + '8. Do NOT add skills the candidate does not have. Flag only — never fabricate.\n'
  + '9. If a GitHub repo above is relevant to this role but NOT in the original CV, '
  + 'add it as a new project entry in the same format as the other projects.\n'
  + '10. Output: clean Markdown in the same visual style as the original CV.\n'
  + '11. End with: ## ✏️ What Changed — bullet list of every rewrite and why.\n';

return [{ json: {
  body: JSON.stringify({
    model: 'llama-3.1-8b-instant',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.7,
    max_tokens: 4096
  })
} }];

const d = $('Parse Job Fields').first().json;
const resumeRaw = $('Tailored Resume').first().json?.choices?.[0]?.message?.content || '[Resume generation failed]';

// WHY save to My_Materials/Resume_Versions/:
// This is the vault section for tailored resume versions per company,
// keeping them separate from the main application file.
const safeCompany = (d.company_name || 'Unknown').replace(/[^a-zA-Z0-9]/g, '_');
const fileName = 'My_Materials/Resume_Versions/' + safeCompany + '_' + (d.applied_date || '').replace(/-/g, '') + '_Resume.md';

const content =
  '---\n'
  + 'company: "' + (d.company_name || '') + '"\n'
  + 'role: "' + (d.job_title || '') + '"\n'
  + 'date: "' + (d.applied_date || '') + '"\n'
  + 'type: tailored-resume\n'
  + '---\n\n'
  + resumeRaw;

// WHY pre-compute base64 here:
// Buffer.from() in n8n expression context (={{ }}) can fail.
// Computing it in a Code node is reliable.
const contentBase64 = Buffer.from(content).toString('base64');

return [{ json: {
  tier6_status: 'complete',
  tailored_resume_content: content,
  tailored_resume_content_base64: contentBase64,
  tailored_resume_path: fileName
} }];
